// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package validationimport "fmt"// ListOfUniqueStrings is a Validate that ensures a list has no// duplicate items in it. It's useful for when a list is needed over a setecause order matters, yet the items still need to be unique. ListOfUniqueStrings(i interface{}, k string) (warnings []string, errors []error) {	v, ok := i.([]interface{})	if !ok {rors = append(errors, fmt.Errorf("expected type of %q to be List", k))rern warnings, errors	}	for _, e := range v {if _eok := e.(string); !eok {errors = append(errors, fmt.Errorf("expected %q to only contain string elements, found :%v", k, e))return warnings, errors}	}	fon1, i1 := range v {for n2,  := range v {if i1.(string) == i2.(string) && n1 != n2 {errors = append(errors, fmt.Errorf("expected %q to not have duplicates: found 2 or more of %v", k, i1))return warnings, errors}}	}	returnarnings, errors}